# Extended shapes module - inherits from geometry

from geometry import Shape, Point

class Circle(Shape):
    center: Point
    radius: float

    def __init__(self, center: Point, radius: float):
        super().__init__("Circle")
        self.center = center
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return self.name + " with radius " + str(self.radius)

class Triangle(Shape):
    base: float
    height: float

    def __init__(self, base: float, height: float):
        super().__init__("Triangle")
        self.base = base
        self.height = height

    @override
    def area(self) -> float:
        return 0.5 * self.base * self.height
